INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'bac6140c-ea8f-4f22-a633-301e28fd9f73',
  '00000000-0000-0000-0000-000000000001',
  $escape$Gin Project Structure — MVC vs Vertical Slice and When to Switch$escape$,
  $escape$The default instinct with Gin is MVC: split into `handlers/`, `services/`, `models/`, `routes/`. This works fine at small scale, but as features grow you end up chasing a single user-registration flow across four directories. Vertical slice flips this — group by feature, not layer. A `features/auth/` folder owns its handler, service, repository, and DTOs. Your `router.go` just calls `auth.RegisterRoutes(r)`, where each feature exposes a `RegisterRoutes(rg *gin.RouterGroup)` function. Middleware stays global in `middleware/` since it's truly cross-cutting. Gin's `RouterGroup` is the key primitive here — each feature receives its own group and mounts its own routes, keeping coupling minimal. For a `RouterGroup`-per-feature pattern, pass `*gin.Engine` into a bootstrap function and let each package call `engine.Group("/auth")`. Repository interfaces live inside each feature package, not a shared `db/` folder — this enforces boundaries and makes extraction to a microservice a folder-move, not a refactor. Stick with MVC until you hit ~5 features; migrate slice-by-slice after that.$escape$,
  $escape$// main.go
func main() {
    r := gin.Default()
    r.Use(middleware.RequestID())

    v1 := r.Group("/api/v1")
    auth.RegisterRoutes(v1, db)
    posts.RegisterRoutes(v1, db)

    r.Run(":8080")
}

// features/auth/routes.go
func RegisterRoutes(rg *gin.RouterGroup, db *pgxpool.Pool) {
    h := NewHandler(NewService(NewRepository(db)))
    g := rg.Group("/auth")
    g.POST("/login", h.Login)
    g.POST("/register", h.Register)
}$escape$,
