INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '66b59cdf-d63a-4bb6-baf9-36b545e81dd9',
  '00000000-0000-0000-0000-000000000001',
  $escape$Gin DI — Manual Wiring vs Containers and What It Means for Testability$escape$,
  $escape$Gin ships with no DI container. That's a feature, not a gap. The idiomatic pattern is closure-based handler factories: your handler function closes over its dependencies, keeping the gin.HandlerFunc signature clean. This pays off immediately in tests — swap a real `UserRepository` for a mock struct and call the handler directly, no HTTP stack required.

Where teams go wrong is reaching for global state (`var db *gorm.DB` at package level) to avoid the wiring ceremony. This makes unit tests impossible without side effects and kills parallelism.

For larger projects, Google Wire or Uber's dig compose the dependency graph at compile/startup time without runtime reflection overhead. Wire generates explicit Go code you can read; dig resolves by type at runtime. Both integrate cleanly with Gin: build your service graph first, then pass leaf dependencies into your router setup via `SetupRouter(svc *UserService) *gin.Engine`.

The rule: keep `gin.HandlerFunc` as a thin shell. Push logic into injected services. Your handler becomes a one-liner that calls a service method — trivially testable, trivially swappable.$escape$,
  $escape$// Handler factory — dependency injected via closure
func NewUserHandler(svc UserService) gin.HandlerFunc {
	return func(c *gin.Context) {
		id := c.Param("id")
		user, err := svc.GetByID(c.Request.Context(), id)
		if err != nil {
			c.JSON(http.StatusNotFound, gin.H{"error": err.Error()})
			return
		}
		c.JSON(http.StatusOK, user)
	}
}

// Router wiring — dependencies composed outside Gin
func SetupRouter(svc UserService) *gin.Engine {
	r := gin.New()
	r.GET("/users/:id", NewUserHandler(svc))
	return r
}$escape$,
