INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '50ca749f-01b1-416c-8c6f-a396d8ef3b83',
  '00000000-0000-0000-0000-000000000001',
  $escape$Gin + GORM — Squashing N+1 Queries and Choosing the Right Database Layer$escape$,
  $escape$Gin handlers don't care which database layer you use, but the choice shapes your entire codebase. GORM is the dominant full ORM in gin projects — it handles migrations, associations, and hooks, but at the cost of SQL transparency. sqlx sits at the other end: raw SQL with struct scanning, full control, no magic. sqlc goes further — write SQL, get type-safe Go structs generated at build time, zero reflection overhead.

The N+1 trap hits hardest with GORM. A handler that fetches posts and loops to load comments fires one query per post. Fix it with Preload: `db.Preload("Comments").Find(&posts)` emits exactly two queries regardless of result size — one for posts, one for comments using an IN clause.

For migrations, never rely on AutoMigrate in production — it won't drop columns or handle multi-step changes safely. Use golang-migrate with versioned .sql files and run migrations as an explicit step in your GitHub Actions workflow before the gin server container starts.

If query performance is critical, profile with GORM's built-in logger set to `logger.Info` mode — it prints every SQL statement and execution time directly to your gin server output.$escape$,
  $escape$// N+1 anti-pattern inside a gin handler
func GetPostsNaive(c *gin.Context) {
	var posts []Post
	db.Find(&posts)
	for i := range posts {
		db.Where("post_id = ?", posts[i].ID).Find(&posts[i].Comments) // 1 query per post
	}
	c.JSON(http.StatusOK, posts)
}

// Fix: Preload collapses N+1 into 2 queries
func GetPosts(c *gin.Context) {
	var posts []Post
	if err := db.Preload("Comments").Find(&posts).Error; err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}
	c.JSON(http.StatusOK, posts)
}$escape$,
