INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3bcb36be-000c-4dd1-b3a0-a3c53b7b9230',
  '00000000-0000-0000-0000-000000000001',
  $escape$Gin Input Validation — Binding, Sanitization, and Error Responses at the Boundary$escape$,
  $escape$Gin's `ShouldBindJSON` (or `ShouldBind` for form data) is your validation boundary. Pair it with `go-playground/validator` tags directly on your request struct — `binding:"required,email,max=255"` — and Gin wires validation automatically on bind. Never trust raw input past this layer.

When `ShouldBindJSON` returns an error, cast it to `validator.ValidationErrors` to extract field-level failures and map them to human-readable messages. Return structured JSON errors — never expose raw validator output to clients.

For sanitization, strip HTML before persisting: use `microcosm-cc/bluemonday` after binding succeeds. Don't sanitize in the struct; do it explicitly in your handler or a thin service layer so the boundary stays clear.

Avoid `c.BindJSON` — it writes a `400` automatically on failure, robbing you of control over the error shape. `ShouldBindJSON` gives you full control. Register a custom `ErrorHandler` middleware to normalize all validation errors into a consistent `{ errors: [{field, message}] }` envelope across every route.$escape$,
  $escape$type CreatePostRequest struct {
	Title   string `json:"title" binding:"required,min=3,max=120"`
	Content string `json:"content" binding:"required,max=5000"`
	Email   string `json:"email" binding:"required,email"`
}

func CreatePost(c *gin.Context) {
	var req CreatePostRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		var ve validator.ValidationErrors
		if errors.As(err, &ve) {
			out := make([]gin.H, len(ve))
			for i, fe := range ve {
				out[i] = gin.H{"field": fe.Field(), "message": fe.Tag()}
			}
			c.JSON(http.StatusUnprocessableEntity, gin.H{"errors": out})
			return
		}
		c.JSON(http.StatusBadRequest, gin.H{"error": "invalid request"})
		return
	}
	req.Content = bluemonday.StrictPolicy().Sanitize(req.Content)
	c.JSON(http.StatusCreated, gin.H{"status": "ok"})
}$escape$,
  $escape$go$escape$,
