INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '53497ad9-0444-4df6-a3c1-45fbfc7102f5',
  '00000000-0000-0000-0000-000000000001',
  $escape$gin Auth Middleware — JWT Validation and Context Propagation$escape$,
  $escape$gin's middleware system makes JWT validation clean: register once on a RouterGroup, and every downstream handler inherits the auth context. Use gin.Context.Set/Get to pass parsed claims downstream — avoid re-parsing the token in each handler.

The key pattern is a custom gin.HandlerFunc that calls c.Abort() on failure and c.Next() on success. Always call c.AbortWithStatusJSON() instead of just c.Abort() so the response is written immediately and no further handlers execute.

For session handling, store only the user ID in the JWT claims and re-fetch the full user from cache (Redis) or DB in a separate middleware layer — don't trust mutable fields like roles directly from the token. This lets you revoke sessions server-side without waiting for token expiry.

Group protected routes under a single RouterGroup with the middleware applied: r.Group("/api").Use(AuthMiddleware()). Public routes stay on the root engine or a separate group — no accidental auth bypass from missed per-route registration.$escape$,
  $escape$func AuthMiddleware(secret []byte) gin.HandlerFunc {
	return func(c *gin.Context) {
		tokenStr := strings.TrimPrefix(c.GetHeader("Authorization"), "Bearer ")
		token, err := jwt.ParseWithClaims(tokenStr, &Claims{}, func(t *jwt.Token) (interface{}, error) {
			if _, ok := t.Method.(*jwt.SigningMethodHMAC); !ok {
				return nil, fmt.Errorf("unexpected signing method: %v", t.Header["alg"])
			}
			return secret, nil
		})
		if err != nil || !token.Valid {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": "invalid token"})
			return
		}
		c.Set("userID", token.Claims.(*Claims).UserID)
		c.Next()
	}
}$escape$,
  $escape$go$escape$,
