INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2c7b03e9-3cb8-4753-afd6-88031795346a',
  '00000000-0000-0000-0000-000000000001',
  $escape$Gin Testing — Unit vs Integration, Mocking HTTP, and Test Database Strategy$escape$,
  $escape$Gin's `gin.New()` vs `gin.Default()` matters in tests: skip the logger/recovery middleware noise by using `gin.New()` directly. For unit tests, isolate handler logic by calling it with a synthetic `*gin.Context` constructed via `httptest.NewRecorder()` and `http.NewRequest()`. For integration tests, spin up the full router with `gin.SetMode(gin.TestMode)` and drive it through `httptest.NewServer` or directly via `router.ServeHTTP(w, req)`.

For mocking downstream HTTP calls, inject an `*http.Client` into your service and swap it with `httptest.NewServer` returning canned responses — no external dependencies needed. Avoid global state in handlers; constructor injection makes this trivial.

For database strategy, use a separate test schema with `testcontainers-go` spinning up a real Postgres instance. Run migrations before each suite via `golang-migrate`. Never mock the DB layer in integration tests — Gin's real value is in the full request→handler→DB roundtrip. Use `t.Cleanup` to truncate tables between cases, not between suites.$escape$,
  $escape$func TestCreateUser_Integration(t *testing.T) {
	gin.SetMode(gin.TestMode)
	router := gin.New()
	router.POST("/users", handlers.CreateUser(db))

	body := `{"name":"alice","email":"alice@example.com"}`
	w := httptest.NewRecorder()
	req := httptest.NewRequest(http.MethodPost, "/users", strings.NewReader(body))
	req.Header.Set("Content-Type", "application/json")

	router.ServeHTTP(w, req)

	assert.Equal(t, http.StatusCreated, w.Code)
	assert.Contains(t, w.Body.String(), "alice")
}$escape$,
  $escape$go$escape$,
