INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '703433fb-769f-49c2-9d69-9c8015386c5b',
  '00000000-0000-0000-0000-000000000001',
  $escape$Gin API Versioning — Route Groups, Middleware, and Swagger in One Setup$escape$,
  $escape$Gin's `RouterGroup` is the cleanest primitive for REST versioning. Wrap each version in its own group and attach version-specific middleware without polluting the global chain.

Use `gin.New()` over `gin.Default()` in production — you control exactly which middleware runs. Attach `gin.Logger()` and `gin.Recovery()` explicitly, then layer version groups on top.

For OpenAPI generation, `swaggo/swag` integrates directly with Gin via `ginSwagger` and `swaggerFiles`. Annotate handlers with `// @Router /v1/users [get]` doc comments, run `swag init`, and mount the UI at `/swagger/*any` inside a non-versioned group so it doesn't inherit version middleware.

Keep `/v1` and `/v2` groups under a shared `/api` parent group — this lets you attach rate limiting or auth middleware once at the `/api` level. Never version at the subdomain level unless you control DNS; path versioning is simpler to route in Gin and easier to document with swag.$escape$,
  $escape$r := gin.New()
r.Use(gin.Logger(), gin.Recovery())

api := r.Group("/api")
api.Use(AuthMiddleware())

v1 := api.Group("/v1")
{
    v1.GET("/users", handlers.ListUsersV1)
    v1.POST("/users", handlers.CreateUserV1)
}

v2 := api.Group("/v2")
{
    v2.GET("/users", handlers.ListUsersV2) // cursor-based pagination
}

// Swagger outside versioned groups
r.GET("/swagger/*any", ginSwagger.WrapHandler(swaggerFiles.Handler))$escape$,
  $escape$go$escape$,
