INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'fc4e499a-a801-4d52-a158-327902fa8e49',
  '00000000-0000-0000-0000-000000000001',
  $escape$gin — Structured Logs, Correlation IDs, and Request Middleware$escape$,
  $escape$gin's default `gin.Logger()` middleware writes unstructured text — useless for log aggregators like Loki or Datadog. Replace it with a custom `gin.HandlerFunc` that injects a correlation ID and emits structured JSON on every request.

Use `c.Set("request_id", id)` to attach the ID to the context, then retrieve it downstream with `c.GetString("request_id")` in any handler or service call. Pair this with `log/slog` (Go 1.21+) or `zerolog` to emit structured fields.

Key fields to log: `request_id`, `method`, `path`, `status`, `latency`, and `client_ip` (via `c.ClientIP()`). Read latency by capturing `time.Now()` before calling `c.Next()`, then diffing after. For inbound correlation IDs from upstream services, check `c.GetHeader("X-Request-ID")` first and fall back to a fresh UUID — this preserves trace continuity across service boundaries. Register the middleware with `r.Use(RequestLogger())` before any route groups so every route is covered.$escape$,
  $escape$func RequestLogger() gin.HandlerFunc {
	return func(c *gin.Context) {
		start := time.Now()
		reqID := c.GetHeader("X-Request-ID")
		if reqID == "" {
			reqID = uuid.NewString()
		}
		c.Set("request_id", reqID)
		c.Header("X-Request-ID", reqID)
		c.Next()
		slog.Info("request",
			"request_id", reqID,
			"method", c.Request.Method,
			"path", c.FullPath(),
			"status", c.Writer.Status(),
			"latency_ms", time.Since(start).Milliseconds(),
			"client_ip", c.ClientIP(),
		)
	}
}$escape$,
