INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '94bcbb04-a38e-40fd-ba3a-9edb8afe8832',
  '00000000-0000-0000-0000-000000000001',
  $escape$Gin Dev Tooling — Hot Reload with Air and OpenAPI Docs with Swag$escape$,
  $escape$Two tools every Gin developer should have wired in from day one: `air` and `swag`.

`air` watches your Go source files and rebuilds/restarts your Gin server on save — no manual `go run main.go` cycles. Drop an `.air.toml` at your repo root, set `cmd = "go build -o ./tmp/main ."` and `bin = "./tmp/main"`, and run `air`. It respects your build tags and handles `gin.SetMode(gin.DebugMode)` cleanly.

`swag` generates OpenAPI 3.0 spec and a Swagger UI directly from annotations on your Gin handler functions. Annotate your handlers with `// @Summary`, `// @Router /users [get]`, `// @Success 200 {object} UserResponse`, then run `swag init`. Wire the generated UI into Gin with `ginSwagger.WrapHandler` — your API is self-documenting with zero extra maintenance.

For scaffolding, `gonew` (Go 1.22+) can bootstrap a Gin project from a template module. Pair it with a `Makefile` that runs `swag init && air` in one command for a tight inner dev loop.$escape$,
  $escape$// main.go — wire Swagger UI into Gin
import (
    ginSwagger "github.com/swaggo/gin-swagger"
    swaggerFiles "github.com/swaggo/files"
    _ "yourmodule/docs" // generated by swag init
)

func main() {
    r := gin.Default()
    r.GET("/swagger/*any", ginSwagger.WrapHandler(swaggerFiles.Handler))
    r.Run(":8080")
}

// Handler annotation consumed by swag
// @Summary Get user by ID
// @Router /users/{id} [get]
// @Success 200 {object} UserResponse
func GetUser(c *gin.Context) { ... }$escape$,
  $escape$go$escape$,
