INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'a91e29df-05e5-4297-aa4f-be26598bda3f',
  '00000000-0000-0000-0000-000000000001',
  $escape$Gin Background Jobs — Goroutine Workers, Task Queues, and Scheduled Tasks$escape$,
  $escape$Gin has no built-in job system, so background work lives alongside your router in `main()`. The safest pattern: spin up worker goroutines before calling `r.Run()`, communicating via buffered channels. Never pass `*gin.Context` directly into a goroutine — call `c.Copy()` first, since the context is reused by the pool after the handler returns.

For task queues, pair Gin with `asynq` (Redis-backed): enqueue tasks inside handlers using `client.Enqueue()`, then run `asynq.NewServer()` in a separate goroutine. This keeps your HTTP layer decoupled from processing.

For scheduled jobs, `robfig/cron` integrates cleanly — instantiate the scheduler before `r.Run()`, register jobs with `c.AddFunc("@every 1h", handler)`, and call `c.Start()`. Both the cron scheduler and Gin share the same process, so coordinate shutdown with a `context.WithCancel` and `os.Signal` listener calling `srv.Shutdown()` and `c.Stop()` in sequence. Avoid `go func()` fire-and-forget — unrecovered panics in detached goroutines will silently kill your worker.$escape$,
  $escape$func main() {
    jobs := make(chan EmailJob, 100)

    // Worker goroutine alongside Gin
    go func() {
        for job := range jobs {
            sendEmail(job)
        }
    }()

    r := gin.Default()
    r.POST("/send", func(c *gin.Context) {
        var job EmailJob
        if err := c.ShouldBindJSON(&job); err != nil {
            c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
            return
        }
        jobs <- job          // non-blocking if buffered channel has room
        c.Status(http.StatusAccepted)
    })

    r.Run(":8080")
}$escape$,
  $escape$go$escape$,
