INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'eb636519-354f-4dbf-9e78-1cf0cbe40336',
  '00000000-0000-0000-0000-000000000001',
  $escape$gin Monitoring — Health Checks, Prometheus Metrics, and Distributed Tracing$escape$,
  $escape$gin integrates cleanly with observability tooling through middleware and route composition. For health checks, register a dedicated `/health` route returning structured JSON — include DB ping, cache reachability, and uptime. Use `gin.Engine`'s route grouping to keep `/internal/*` endpoints separate from public routes, optionally protected by a middleware that checks a shared secret header.

For Prometheus metrics, `github.com/penglongli/gin-metrics` wraps `prometheus/client_golang` and attaches as a single `Use()` call, exposing `/metrics` automatically. It tracks request count, latency histograms, and in-flight requests per route pattern — all labeled with `gin`'s `FullPath()` rather than the raw URL, so `/users/123` and `/users/456` collapse into `/users/:id`.

For distributed tracing, `go.opentelemetry.io/contrib/instrumentation/github.com/gin-gonic/gin/otelgin` injects an OTEL span per request. Call `otelgin.Middleware("service-name")` before your business middleware. Downstream calls that use the request context automatically inherit the trace. Extract `trace_id` from the span and inject it into gin's response headers for client-side correlation.$escape$,
  $escape$package main

import (
    "github.com/gin-gonic/gin"
    ginmetrics "github.com/penglongli/gin-metrics/ginmetrics"
    "go.opentelemetry.io/contrib/instrumentation/github.com/gin-gonic/gin/otelgin"
)

func main() {
    r := gin.New()

    // Distributed tracing
    r.Use(otelgin.Middleware("byteai-api"))

    // Prometheus metrics (exposes /metrics)
    m := ginmetrics.GetMonitor()
    m.SetMetricPath("/metrics")
    m.Use(r)

    // Health check
    internal := r.Group("/internal")
    internal.GET("/health", func(c *gin.Context) {
        c.JSON(200, gin.H{"status": "ok", "db": pingDB()})
    })

    r.Run(":8080")
}$escape$,
  $escape$go$escape$,
